import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Semnale {

	static int sig_type, x, y;
	static final int mod = 1000000007;

	Semnale() {
	}

	static int type1() {
		// Array to store valid sequences ending in 0
		long[][] dp0 = new long[x + 1][y + 1];
		// Array to store valid sequences ending in 1
		long[][] dp1 = new long[x + 1][y + 1];

		for (int i = 0; i <= x; i++) {
			for (int j = 0; j <= y; j++) {
				// Calculate dp1
				if (i == 0 && j == 1) {
					dp1[i][j] = 1;
				} else if (j != 0) {
					dp1[i][j] = dp0[i][j - 1];
				}
				// Calculate dp0
				if (i == 1 && j == 0) {
					dp0[i][j] = 1;
				} else if (i != 0) {
					dp0[i][j] = (dp0[i - 1][j] + dp1[i - 1][j]) % mod;
				}
			}
		}

		// Total count
		long count = dp0[x][y] + dp1[x][y];
		return (int) (count % mod);
	}

	static int type2() {
		// Array to store valid sequences ending in 0
		long[][] dp0 = new long[x + 1][y + 1];
		// Array to store valid sequences ending in 1
		long[][] dp1 = new long[x + 1][y + 1];

		for (int i = 0; i <= x; i++) {
			for (int j = 0; j <= y; j++) {
				// Calculate dp1
				if (i == 0 && (j == 1 || j == 2)) {
					dp1[i][j] = 1;
				} else if (j >= 2) {
					// If number of 1s is more than or equal to 2
					// add the value of the previous step (j-2 1s)
					dp1[i][j] = dp0[i][j - 1];
					dp1[i][j] += dp0[i][j - 2];
				} else if (j != 0) {
					dp1[i][j] = dp0[i][j - 1];
				}
				// Calculate dp0
				if (i == 1 && j == 0) {
					dp0[i][j] = 1;
				} else if (i != 0) {
					dp0[i][j] = (dp0[i - 1][j] + dp1[i - 1][j]) % mod;
				}
			}
		}

		// Total count
		long count = dp0[x][y] + dp1[x][y];
		return (int) (count % mod);
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("semnale.in"));

			sig_type = sc.nextInt();
			x = sc.nextInt();
			y = sc.nextInt();

			int ans;
			switch (sig_type) {
				case 1:
					ans = Semnale.type1();
					break;
				case 2:
					ans = Semnale.type2();
					break;
				default:
					ans = -1;
					System.out.println("wrong task number");
			}

			try {
				FileWriter fw = new FileWriter("semnale.out");
				fw.write(Integer.toString(ans));
				fw.close();

			} catch (IOException e) {
				System.out.println(e.getMessage());
			}

			sc.close();
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}

#include <limits.h>

#include <algorithm>
#include <cstdint>
#include <fstream>
#include <iostream>
#include <vector>

using namespace std;

const int mod = 1000000007;

ifstream fin("semnale.in");
ofstream fout("semnale.out");

int type1(int x, int y) {
  int n = x + 1;
  int m = y;
  vector<int> v;
  v.push_back(1);
  for (int i = 1; i <= n; i++) {
    v.push_back(1);
    for (int j = i - 1; j > 0; j--) v[j] = (v[j] + v[j - 1]) % mod;
    v[0] = 1;
  }

  return v[m];
}

int type2(int x, int y) {
  int n = x + 1;
  int m = y;
  long old_j = 0;
  vector<long> v;

  // create the first row of Pascal's triangle matrix
  v.push_back(1);
  v.push_back(2);
  v.push_back(3);
  v.push_back(2);
  v.push_back(1);
  v.push_back(0);
  v.push_back(0);

  // compute the rest of Pascal's triangle matrix
  for (long i = 3; i <= n; i++) {
    for (long j = v.size() - 1; j > 0; j--) {
      if (j == v.size() - 1)
        // the last element of the row need only the last two elements
        v[j] = (v[j - 1] + v[j - 2]) % mod;
      else if (j == 1)
        // second element of the row need only the first two elements
        v[j] = (v[j] + v[j - 1]) % mod;
      else
        // the rest of the elements need the last three elements
        v[j] = ((v[j] + v[j - 1]) % mod + v[j - 2]) % mod;
    }
    v[0] = 1;
    // add the last two elements
    v.push_back(0);
    v.push_back(0);
  }

  return v[m];
}

int main() {
  int sig_type, x, y;

  fin >> sig_type >> x >> y;

  switch (sig_type) {
    case 1:
      fout << type1(x, y);
      break;
    case 2:
      fout << type2(x, y);
      break;
    default:
      fout << "wrong task number" << endl;
  }

  return 0;
}
